class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        int n = arr.size();
        int sum = 0;
        for (int num : arr) sum += num;
        if (sum <= target) return *max_element(arr.begin(), arr.end());

        int l = 0, r = *max_element(arr.begin(), arr.end());
        int res = r;
        while (l <= r) {
            int mid = l + (r - l) / 2;
            int curSum = 0;
            for (int num : arr) curSum += min(num, mid);
            if (curSum == target) return mid;
            if (curSum < target) {
                l = mid + 1;
            } else {
                r = mid - 1;
                res = mid;
            }
        }
        int sum1 = 0, sum2 = 0;
        for (int num : arr) sum1 += min(num, res - 1);
        for (int num : arr) sum2 += min(num, res);
        if (abs(sum1 - target) < abs(sum2 - target) || (abs(sum1 - target) == abs(sum2 - target) && res - 1 < res)) return res - 1;
        return res;
    }
};

